DISK="$STORE/windows-arm.raw"

# shellcheck source=/dev/null
source "$ROOT/tests/integration/windows-arm-hvf-pflash-fixtures.sh"

install_backend_guards "Windows Arm HVF firmware run-loop runner smoke"
